function Cops(input) {
    const lines = input.trim().split('\n');
    const T = parseInt(lines[0]); // Number of test cases

    let index = 1; // Index to iterate through test cases

    // Iterate through each test case
    for (let t = 0; t < T; t++) {
        const [M, x, y] = lines[index++].split(' ').map(Number); // Number of cops, speed of cops, and search time
        const copHouses = lines[index++].split(' ').map(Number); // Houses where cops are residing

        // Initialize an array to mark safe houses
        const safeHouses = new Array(100).fill(true);

        // Mark houses where cops can reach within y minutes
        for (let i = 0; i < M; i++) {
            const copHouse = copHouses[i];
            const startHouse = Math.max(1, copHouse - x * y);
            const endHouse = Math.min(100, copHouse + x * y);
            for (let j = startHouse; j <= endHouse; j++) {
                safeHouses[j - 1] = false; // Houses are 0-indexed
            }
        }

        // Count safe houses
        let countSafeHouses = 0;
        for (let i = 0; i < 100; i++) {
            if (safeHouses[i]) {
                countSafeHouses++;
            }
        }

        console.log(countSafeHouses); // Output the number of safe houses
    }
}

process.stdin.setEncoding('utf8');
let input = '';
process.stdin.on('data', function(chunk) {
    input += chunk;
});

process.stdin.on('end', function() {
    Cops(input);
